import React, { useState, useEffect } from 'react';
import './App.css';

const gridSize = 8;

const baseCharacters = [
  { name: 'Knight', hp: 100, atk: 30, moveRange: 3, sprite: '/sprites/knight.png' },
  { name: 'Archer', hp: 80, atk: 25, moveRange: 4, sprite: '/sprites/archer.png' },
  { name: 'Mage', hp: 70, atk: 40, moveRange: 3, sprite: '/sprites/mage.png' },
  { name: 'Healer', hp: 90, atk: 10, moveRange: 3, sprite: '/sprites/healer.png' },
  { name: 'Warrior', hp: 110, atk: 35, moveRange: 2, sprite: '/sprites/warrior.png' },
  { name: 'Rogue', hp: 75, atk: 30, moveRange: 5, sprite: '/sprites/rogue.png' },
  { name: 'Summoner', hp: 65, atk: 45, moveRange: 2, sprite: '/sprites/summoner.png' },
  { name: 'Paladin', hp: 95, atk: 20, moveRange: 3, sprite: '/sprites/paladin.png' },
];

let idCounter = 1;
const generateTeam = (team, row) =>
  baseCharacters.map((c, i) => ({
    ...c,
    id: idCounter++,
    x: i,
    y: row,
    team,
  }));

const initialCharacters = [...generateTeam('A', 0), ...generateTeam('B', gridSize - 1)];

function App() {
  const [characters, setCharacters] = useState(initialCharacters);
  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');
  const [moveLeft, setMoveLeft] = useState(0);

  const selectedChar = characters.find(c => c.id === selectedId);

  useEffect(() => {
    if (selectedChar && selectedChar.team === turn && selectedChar.hp > 0) {
      setMoveLeft(selectedChar.moveRange);
    } else {
      setMoveLeft(0);
    }
  }, [selectedId, turn, selectedChar]);

  const moveCharacter = (id, dx, dy) => {
    if (moveLeft <= 0) return;

    setCharacters(prev =>
      prev.map(c => {
        if (c.id === id && c.team === turn) {
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          const occupied = prev.some(
            other => other.id !== id && other.x === newX && other.y === newY && other.hp > 0
          );
          if (occupied) return c;
          return { ...c, x: newX, y: newY };
        }
        return c;
      })
    );

    setMoveLeft(prev => prev - 1);
  };

  const attack = attackerId => {
    const attacker = characters.find(c => c.id === attackerId);
    if (!attacker || attacker.hp <= 0) return;

    const targets = characters.filter(
      c =>
        c.team !== attacker.team &&
        c.hp > 0 &&
        Math.abs(c.x - attacker.x) + Math.abs(c.y - attacker.y) === 1
    );

    if (targets.length > 0) {
      const target = targets[0];
      setCharacters(prev =>
        prev.map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c
        )
      );
    }
  };

  const endTurn = () => {
    setSelectedId(null);
    setTurn(prev => (prev === 'A' ? 'B' : 'A'));
    setMoveLeft(0);
  };

  return (
    <div className="App" style={{ padding: '20px' }}>
      <h1>DuelGrid</h1>
      <h2>Turn: Team {turn}</h2>

      <div className="grid" style={{ border: '2px solid #444', backgroundColor: '#111', display: 'inline-block' }}>
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row" style={{ display: 'flex' }}>
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find(c => c.x === x && c.y === y && c.hp > 0);
              return (
                <div
                  key={x}
                  className={`tile ${char ? 'occupied' : ''}`}
                  style={{
                    width: 60,
                    height: 60,
                    border: '1px solid #555',
                    backgroundColor:
                      selectedId === (char && char.id) ? '#444' : '#222',
                    position: 'relative',
                    cursor: char && char.team === turn ? 'pointer' : 'default',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexDirection: 'column',
                    color: 'white',
                    fontSize: 11,
                    userSelect: 'none',
                  }}
                  onClick={() => {
                    if (char && char.team === turn && char.hp > 0) setSelectedId(char.id);
                  }}
                >
                  {char && (
                    <>
                      <img
                        src={char.sprite}
                        alt={char.name}
                        style={{ width: 32, height: 32, pointerEvents: 'none', marginBottom: 4 }}
                      />
                      <div>{char.name}</div>
                      <div>HP: {char.hp}</div>
                      <div>ATK: {char.atk}</div>
                    </>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      <div className="controls" style={{ marginTop: 20 }}>
        {selectedChar && selectedChar.team === turn && selectedChar.hp > 0 ? (
          <>
            <div>
              <strong>Selected: {selectedChar.name}</strong>
            </div>
            <div>HP: {selectedChar.hp}</div>
            <div>ATK: {selectedChar.atk}</div>
            <div>Move Range Left: {moveLeft}</div>
            <div style={{ marginTop: 10 }}>
              <button onClick={() => moveCharacter(selectedId, -1, 0)} disabled={moveLeft <= 0} style={{ marginRight: 5 }}>
                ← Move
              </button>
              <button onClick={() => moveCharacter(selectedId, 1, 0)} disabled={moveLeft <= 0} style={{ marginRight: 5 }}>
                → Move
              </button>
              <button onClick={() => moveCharacter(selectedId, 0, -1)} disabled={moveLeft <= 0} style={{ marginRight: 5 }}>
                ↑ Move
              </button>
              <button onClick={() => moveCharacter(selectedId, 0, 1)} disabled={moveLeft <= 0} style={{ marginRight: 5 }}>
                ↓ Move
              </button>
            </div>
            <div style={{ marginTop: 10 }}>
              <button onClick={() => attack(selectedId)} style={{ marginRight: 10 }}>
                Attack
              </button>
              <button onClick={endTurn}>End Turn</button>
            </div>
          </>
        ) : (
          <div>Select your character to move or attack</div>
        )}
      </div>
    </div>
  );
}

export default App;
